30	// Patterns for extracting explicit commitments from bead descriptions.
31	// A commitment is a durable anchor that must survive a replacement rewrite.
32	var (
33		reGoverningRef = regexp.MustCompile(`\b[A-Z]{2,6}-\d{3,}\b`)
34		reNamedTest    = regexp.MustCompile(`\bTest[A-Z]\w+\b`)
35		reFileLine     = regexp.MustCompile(`\b[\w/.-]+\.go:\d+\b`)
36		reDepID        = regexp.MustCompile(`\bddx-[0-9a-f]{8}\b`)
37	)
38	
39	var descriptionSectionHeaders = []string{
40		"PROBLEM", "ROOT CAUSE", "PROPOSED FIX", "NON-SCOPE", "NON SCOPE",
41		"CONTEXT", "PARENT", "DEPS", "DEPENDENCIES", "BACKGROUND",
42	}
43	
44	func isDescriptionSectionHeader(line string) bool {
45		upper := strings.ToUpper(strings.TrimRight(normalizeWhitespace(line), ":"))
46		for _, h := range descriptionSectionHeaders {
47			if upper == h {
48				return true
49			}
50		}
51		return false
52	}
53	
54	// extractNonScopeBullets returns normalized bullet text from the NON-SCOPE
55	// section of a bead description.
56	func extractNonScopeBullets(desc string) []string {
57		lines := strings.Split(desc, "\n")
58		var inNonScope bool
59		var result []string
60		for _, line := range lines {
61			trimmed := strings.TrimSpace(line)
62			upper := strings.ToUpper(strings.TrimRight(normalizeWhitespace(trimmed), ":"))
63			if upper == "NON-SCOPE" || upper == "NON SCOPE" {
64				inNonScope = true
65				continue
66			}
67			if inNonScope {
68				if trimmed == "" {
69					continue
70				}
71				if isDescriptionSectionHeader(trimmed) {
72					inNonScope = false
73					continue
74				}
75				bullet := strings.TrimLeft(trimmed, "-•*+# ")
76				bullet = normalizeWhitespace(bullet)
77				if bullet != "" {
78					result = append(result, bullet)
79				}
80			}
81		}
82		return result
83	}
84	
85	// extractDescriptionCommitments returns durable anchor strings that must be
86	// preserved across a description replacement rewrite:
87	//   - Governing artifact references (FEAT-010, ADR-023, etc.)
88	//   - Named test functions (TestFoo)
89	//   - File:line references (pkg/file.go:42)
90	//   - Dependency IDs (ddx-XXXXXXXX)
91	//   - NON-SCOPE section bullet points (prefixed with "non_scope:")
92	func extractDescriptionCommitments(desc string) []string {
93		seen := make(map[string]struct{})
94		var result []string
95		add := func(s string) {
96			if _, ok := seen[s]; !ok {
97				seen[s] = struct{}{}
98				result = append(result, s)
99			}
100		}
101		for _, m := range reGoverningRef.FindAllString(desc, -1) {
102			add(m)
103		}
104		for _, m := range reNamedTest.FindAllString(desc, -1) {
105			add(m)
106		}
107		for _, m := range reFileLine.FindAllString(desc, -1) {
108			add(m)
109		}
110		for _, m := range reDepID.FindAllString(desc, -1) {
111			add(m)
112		}
113		for _, bullet := range extractNonScopeBullets(desc) {
114			add("non_scope:" + bullet)
115		}
116		return result
117	}
118	
119	// validateDescriptionReplacement checks that all explicit commitments in the
120	// old description are preserved in the new description. It returns the list of
121	// preservation evidence entries recorded. An error is returned if any
122	// commitment is missing from the replacement.
123	func validateDescriptionReplacement(oldDesc, newDesc string) ([]string, error) {
124		commitments := extractDescriptionCommitments(oldDesc)
125		normNew := normalizeWhitespace(newDesc)
126		var evidence []string
127		for _, c := range commitments {
128			if strings.HasPrefix(c, "non_scope:") {
129				checkIn := strings.TrimPrefix(c, "non_scope:")
130				if !strings.Contains(normNew, checkIn) {
131					return nil, fmt.Errorf("pre-claim intake rewrite: description drops commitment %q", c)
132				}
133			} else {
134				if !strings.Contains(newDesc, c) {
135					return nil, fmt.Errorf("pre-claim intake rewrite: description drops commitment %q", c)
136				}
137			}
138			evidence = append(evidence, c)
139		}
140		return evidence, nil
141	}
