275	func snapshotPreClaimIntakeRewrite(description, acceptance string) preClaimIntakeRewriteSnapshot {
276		return preClaimIntakeRewriteSnapshot{
277			DescriptionBytes: len(description),
278			AcceptanceBytes:  len(acceptance),
279			DescriptionSHA:   hashText(description),
280			AcceptanceSHA:    hashText(acceptance),
281		}
282	}
283	
284	func hashText(text string) string {
285		sum := sha256.Sum256([]byte(text))
286		return hex.EncodeToString(sum[:])
287	}
288	
289	// acceptancePreservesCriteria returns true when the rewritten acceptance field
290	// ("after") contains all verifiable assertions from the original ("before").
291	//
292	// Structural reformatting — renumbering ("AC1." → "1."), reordering,
293	// normalising whitespace, or splitting one unnumbered sentence into several
294	// numbered criteria — is treated as preserving the criteria, not dropping them.
295	//
296	// A drop is detected only when the original had parseable numbered criteria and
297	// one or more of those criteria bodies are absent from the rewrite.
298	//
299	// When the original has no parseable numbered criteria (e.g. a single vague
300	// sentence), any rewrite that adds structured numbered criteria is accepted as
301	// an expansion; a rewrite that only rephrases the same prose content is checked
302	// by full-text containment.
303	func acceptancePreservesCriteria(before, after string) bool {
304		beforeCriteria := parseAcceptanceCriteria(before)
305		afterCriteria := parseAcceptanceCriteria(after)
306	
307		// If the original had no parseable numbered criteria, use a lenient path:
308		// any rewrite that introduces numbered criteria is an expansion (always
309		// accepted). If the rewrite is also unstructured, fall back to full-text
310		// containment on the normalised bodies.
311		if len(beforeCriteria) == 0 {
312			if len(afterCriteria) > 0 {
313				// Unstructured original → structured rewrite: expansion always allowed.
314				return true
315			}
316			normBefore := normalizeWhitespace(strings.TrimSpace(before))
317			normAfter := normalizeWhitespace(strings.TrimSpace(after))
318			if normBefore == "" {
319				return true
320			}
321			return strings.Contains(normAfter, normBefore)
322		}
323	
324		// Original had structured numbered criteria. Require each criterion body to
325		// appear in at least one criterion body of the rewrite (either verbatim or
326		// as a substring). The count check is a fast early-exit: if fewer criteria
327		// are present in the rewrite there must be a drop.
328		if len(afterCriteria) == 0 {
329			// Rewrite lost all structure — fall back to full-text containment of
330			// each criterion body inside the normalised rewrite text.
331			normAfter := normalizeWhitespace(strings.TrimSpace(after))
332			for _, criterion := range beforeCriteria {
333				if !strings.Contains(normAfter, criterion) {
334					return false
335				}
336			}
337			return true
338		}
339	
340		if len(afterCriteria) < len(beforeCriteria) {
341			return false
342		}
343	
344		for _, criterion := range beforeCriteria {
345			found := false
346			for _, candidate := range afterCriteria {
347				if strings.Contains(candidate, criterion) {
348					found = true
349					break
350				}
351			}
352			if !found {
353				return false
354			}
355		}
356		return true
357	}
358	
359	func parseAcceptanceCriteria(raw string) []string {
360		lines := strings.Split(raw, "\n")
361		out := make([]string, 0, len(lines))
362		for _, line := range lines {
363			if body, ok := parseAcceptanceCriterionBody(line); ok {
364				out = append(out, body)
365			}
366		}
367		return out
368	}
369	
370	// parseAcceptanceCriterionBody extracts the verifiable assertion text from a
371	// single acceptance criterion line. It recognises common bullet-prefix
372	// conventions used in bead acceptance fields:
373	//
374	//   - Pure numeric:  "1. body"  "42. body"
375	//   - AC-prefix:     "AC1. body"  "AC2. body"  (letters then digits before ".")
376	//   - Dash/bullet:   "- body"  "• body"  "* body"
377	//
378	// All these forms are normalised so that a reformat (e.g. "AC1." → "1.") does
379	// not appear to have dropped a criterion when the assertion text is identical.
380	func parseAcceptanceCriterionBody(line string) (string, bool) {
381		trimmed := strings.TrimSpace(line)
382		if trimmed == "" {
383			return "", false
384		}
385	
386		// Dash/star/bullet prefix: "- body", "* body", "+ body", "• body"
387		// The bullet character (•, U+2022) is multi-byte in UTF-8, so we use
388		// HasPrefix rather than a byte switch for that case.
389		if len(trimmed) >= 2 {
390			switch trimmed[0] {
391			case '-', '*', '+':
392				body := normalizeWhitespace(trimmed[1:])
393				if body != "" {
394					return body, true
395				}
396			}
397		}
398		if strings.HasPrefix(trimmed, "•") {
399			body := normalizeWhitespace(strings.TrimPrefix(trimmed, "•"))
400			if body != "" {
401				return body, true
402			}
403		}
404	
405		dot := strings.Index(trimmed, ".")
406		if dot <= 0 {
407			return "", false
408		}
409		prefix := trimmed[:dot]
410	
411		// Pure numeric: "1.", "42."
412		if allDigits(prefix) {
413			body := normalizeWhitespace(strings.TrimSpace(trimmed[dot+1:]))
414			if body != "" {
415				return body, true
416			}
417			return "", false
418		}
419	
420		// AC-prefix: letters immediately followed by digits before the dot.
421		// Matches "AC1", "AC12", "A1", etc.
422		if isAlphaNumericBullet(prefix) {
423			body := normalizeWhitespace(strings.TrimSpace(trimmed[dot+1:]))
424			if body != "" {
425				return body, true
426			}
427			return "", false
428		}
429	
430		return "", false
431	}
432	
433	// isAlphaNumericBullet returns true when s looks like a labelled-list prefix
434	// of the form letters+digits (e.g. "AC1", "AC12", "A1"). At least one letter
435	// and one digit must be present; the digits must all trail the letters.
436	func isAlphaNumericBullet(s string) bool {
437		if s == "" {
438			return false
439		}
440		// Find the split point where letters end and digits begin.
441		splitAt := -1
442		for i, r := range s {
443			isLetter := (r >= 'A' && r <= 'Z') || (r >= 'a' && r <= 'z')
444			isDigit := r >= '0' && r <= '9'
445			if !isLetter && !isDigit {
446				return false
447			}
448			if isDigit && splitAt == -1 {
449				splitAt = i
450			}
451			if isLetter && splitAt != -1 {
452				// letter after digit — not a clean ACN prefix
453				return false
454			}
455		}
456		// Must have at least one letter (splitAt > 0) and at least one digit.
457		return splitAt > 0
458	}
459	
460	func allDigits(s string) bool {
461		if s == "" {
462			return false
463		}
464		for _, r := range s {
465			if r < '0' || r > '9' {
466				return false
467			}
468		}
469		return true
470	}
471	
472	func normalizeWhitespace(s string) string {
473		return strings.Join(strings.Fields(strings.TrimSpace(s)), " ")
474	}
475	
476	func hasString(values []string, target string) bool {
477		for _, v := range values {
478			if v == target {
479				return true
480			}
481		}
482		return false
483	}
