3402	// trips. Using the escalation constant avoids string duplication.
3403	func isPerBeadBudgetExhaustedReport(report ExecuteBeadReport) bool {
3404		return strings.Contains(report.Detail, escalation.PerBeadBudgetExhaustedReason)
