1554			// report.Disrupted (e.g. a future SIGKILL/SIGTERM or server-restart
1555			// classifier inside ExecuteBeadWithConfig), preserve it.
1556			if !report.Disrupted && report.Status != ExecuteBeadStatusSuccess {
1557				if reason, disrupted := classifyDisruption(ctx, err); disrupted {
1558					report.Disrupted = true
1559					report.DisruptionReason = reason
1560				}
1561			}
1562			if report.Disrupted {
1563				reason := report.DisruptionReason
1564				if reason == "" {
1565					reason = "unknown"
1566				}
1567				emitDisruptionDetected(emit, w.Store, candidate.ID,
1568					reason, report.Detail, report.Harness, report.Model, assignee, now().UTC())
1569			}
1570	
1571			result.Attempts++
1572			appendExecutionRoutingIntentEvidence(w.Store, candidate, report, now().UTC())
1573	
1574			if attemptOut.StoreErr != nil {
1575				_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
1576					return commitOutcomeError(attemptOut.StoreErrOp, assignee, result, attemptOut.StoreErr)
1577				})
1578			}
1579	
1580			if parking := attemptOut.Parking; parking != nil {
1581				if parking.Unclaim {
1582					if err := w.Store.Unclaim(candidate.ID); err != nil {
1583						_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
1584							return commitOutcomeError("Unclaim", assignee, result, err)
1585						})
1586						if ctx.Err() != nil {
1587							return result, ctx.Err()
1588						}
1589						continue

