280	// decodePreClaimIntakePayloadResult decodes a JSON payload into a PreClaimIntakeResult.
281	// It accepts both the legacy intake schema (classification field) and the canonical
282	// readiness schema (outcome field), converting both into the same decision model.
283	func decodePreClaimIntakePayloadResult(payload string) (PreClaimIntakeResult, error) {
284		var probe struct {
285			Classification  string `json:"classification"`
286			Outcome         string `json:"outcome"`
287			Tractability    string `json:"tractability"`
288			Rationale       string `json:"rationale"`
289			Score           *int   `json:"score"`
290			ReadinessChecks []struct {
291				Reason string `json:"reason,omitempty"`
292			} `json:"readiness_checks"`
293			SuggestedFixes []struct {
294				Target string `json:"target,omitempty"`
295			} `json:"suggested_fixes"`
296		}
297		if err := json.Unmarshal([]byte(payload), &probe); err != nil {
298			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode result: %w", err)
299		}
300		if probe.Outcome != "" {
301			return decodeCanonicalReadinessPayload(payload)
302		}
303		if probe.Classification != "" {
304			if isReadinessClassificationPayload(probe.Classification, probe.Tractability, probe.Rationale, probe.Score, len(probe.ReadinessChecks), len(probe.SuggestedFixes)) {
305				return decodeReadinessClassificationPayload(payload)
306			}
307			return decodeLegacyIntakePayload(payload)
308		}
309		return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: missing classification or outcome field")
310	}
